import{c as t,Q as a,j as r,m as s}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Ben's Bites — 2026-04-21","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-21","date":"2026-04-21T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-21-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-21-bens-bites.md","lastUpdated":1779796674000}`),o={name:"research/ai-news/2026-04/2026-04-21-bens-bites.md"};function n(i,e,l,p,h,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="🍔-ben-s-bites-—-2026-04-21" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-21 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-21" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-21&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="that-s-my-designer-claude" tabindex="-1"><a href="https://www.bensbites.com/p/thats-my-designer-claude" target="_blank" rel="noreferrer">That&#39;s my designer - Claude</a> <a class="header-anchor" href="#that-s-my-designer-claude" aria-label="Permalink to &quot;[That&#39;s my designer - Claude](https://www.bensbites.com/p/thats-my-designer-claude)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-21</em></p><p>Hey folks,</p><p>I’ve been playing a lot with Claude Cowork for my talk at Stanford later today. It’s comically bad for the average jane.</p><p>A lot of capabilities are enabled using connectors and plugins, but if you don’t know that, good luck getting it to do anything. Can’t seem to send emails, install a skill or tell me about what potential connectors are there.</p><p>Scheduled tasks in Cowork stop when you shut the lid, but Routines (similar thing) in Claude Code do not. <a href="https://x.com/claudeai/status/2046328619249684989" target="_blank" rel="noreferrer">Cowork is just now getting Artifacts</a> - the mini apps on the Claude chat app that started the vibe-coding wave.</p><p>I can search for all of this, yes. but an average user will not. and they’ll walk away thinking AI is hype for the next 6 months/a year.</p><p>Anyway, the <a href="https://www.newcomer.co/p/were-back-the-cerebral-valley-ai-34a" target="_blank" rel="noreferrer">Cerebral Valley AI Summit</a> is coming back to London on June 24th. I’m planning to be there.</p><p>Ben’s Bites is brought to you by <a href="https://gauntletai.com/apply?utm_source=Third%20Party&amp;utm_campaign=Bens%20Bites&amp;utm_medium=newsletter&amp;utm_content=" target="_blank" rel="noreferrer">Gauntlet</a></p><p>Most RAG systems fail in production. Gauntlet Night School on Wednesday, April 22 covers how to build one that doesn&#39;t — live and free - <a href="https://us06web.zoom.us/webinar/register/2017762003233/WN_P79TrYY5R8Cru6xEDkwKcw" target="_blank" rel="noreferrer">Register</a>. Or go deeper: become an AI-native engineer at no cost. Cohort starts April 27. <a href="https://gauntletai.com/apply?utm_source=Third%20Party&amp;utm_campaign=Bens%20Bites&amp;utm_medium=newsletter&amp;utm_content=" target="_blank" rel="noreferrer">Apply now</a></p><p>Headlines</p><p><a href="https://www.anthropic.com/news/claude-opus-4-7" target="_blank" rel="noreferrer">Opus 4.7 is out</a> - much better at vision (interpreting images) and efficient at using reasoning tokens. A new xhigh level of thinking now sits between “high” and “max”. I’ve been using it over the weekend at xhigh and didn’t face any issues (despite the general sentiment on Twitter that 4.7 is a regression).</p><p><a href="https://www.anthropic.com/news/claude-design-anthropic-labs" target="_blank" rel="noreferrer">Claude also has a Design tab now</a> - a canvas-like interface with chat on the sidebar to explore wireframes or create high fidelity prototypes. It asks you 5-10 questions via an interactive form and then gets building. I found the <a href="https://x.com/Keshavatearth/status/2045377232965972305" target="_blank" rel="noreferrer">image → design workflow</a> to be really good in the prototype mode. Has separate limits while in research preview, but expect the weekly limits to only last for 2-3 big generations max (on the $20 plan). Check out <a href="https://x.com/petergyang/status/2045181813484884396" target="_blank" rel="noreferrer">Peter’s demo</a> across multiple use cases.</p><p>Codex got a few updates: 1. <a href="https://openai.com/index/codex-for-almost-everything/" target="_blank" rel="noreferrer">Computer Use</a> - it can now use apps on your Mac. I’m not completely sold on it and have <a href="https://x.com/bentossell/status/2045745033530527989" target="_blank" rel="noreferrer">some questions</a>, but it does seem to work a lot faster than previous iterations of computer/browser use demos. Also, it works in the background, so your Mac is free for you to use. 2. <a href="https://developers.openai.com/codex/memories/chronicle" target="_blank" rel="noreferrer">Chronicle</a>, an opt-in preview that uses recent screen context to build memories. 3. A bunch of plugins, including image generation, so that Codex can be the superapp to use AI.</p><p><a href="https://x.com/matanSF/status/2044821889844228378" target="_blank" rel="noreferrer">Factory AI is now valued at $1.5B</a> after their latest raise of $150M. Try the new <a href="https://factory.ai/product/desktop" target="_blank" rel="noreferrer">desktop app for Droid</a>, Factory’s coding agent, with 50% off on Opus 4.7 till 30th April.</p><p>My feed</p><p>Your tools are full of data, but you’re still guessing. <a href="https://www.backstory.ai/get-demo?utm_source=partner&amp;utm_medium=socialpaid&amp;utm_term=bens_bites&amp;utm_content=social&amp;utm_campaign=brand_paid&amp;rls=social&amp;rlsd=" target="_blank" rel="noreferrer">Backstory</a> - Focus on what drives revenue, based on how your business actually sells.*</p><p><a href="https://x.com/OfficialLoganK/status/2046334868481806491" target="_blank" rel="noreferrer">Google AI Pro and Ultra</a> subs now work with AI Studio - higher rate limits for vibe coding in the playground.</p><p><a href="https://x.com/0interestrates/status/2045250990333694331" target="_blank" rel="noreferrer">Julius</a> can now generate slide decks with charts and tables, exportable as pptx.</p><p><a href="https://galaxybrain.com/" target="_blank" rel="noreferrer">Galaxy Brain</a> - an operating system powered by local files. I’m an investor.</p><p><a href="https://x.com/skirano/status/2046318389245972770" target="_blank" rel="noreferrer">Kimi 2.6 Code</a> - a Claude Code-style terminal built specifically for <a href="https://www.kimi.com/blog/kimi-k2-6" target="_blank" rel="noreferrer">Kimi K2.6</a>.</p><p><a href="https://x.com/moondreamai/status/2046265928938291604" target="_blank" rel="noreferrer">Moondream Lens</a> - fine-tune a vision model to production accuracy in hours with as few as 20 images.</p><p>Zapier’s <a href="https://x.com/wadefoster/status/2046214612685590798" target="_blank" rel="noreferrer">AutomationBench</a> measures real work done by models - CRM updates, inbox follow-ups, multi-step tool chains. No model has cracked 10%.</p><p><a href="https://faydakrouri.com/thoughts/how-ai-made-me-a-builder/" target="_blank" rel="noreferrer">How AI made me a builder</a> without losing my taste as a designer.</p><p>Quiver upgrades its models for vector generation - <a href="https://x.com/QuiverAI/status/2044864082180706721" target="_blank" rel="noreferrer">Arrow 1.1 and Arrow 1.1 Max</a>.</p><p><a href="https://acceptmarkdown.com/" target="_blank" rel="noreferrer">acceptmarkdown.com</a> - checks whether your site returns Markdown correctly for agents.</p><p><a href="https://x.com/chrysb/status/2045972791208624541" target="_blank" rel="noreferrer">The 5 stages of AI grief</a>.</p><p>HeyGen open-sourced <a href="https://x.com/HeyGen/status/2044827454460871072" target="_blank" rel="noreferrer">HyperFrames</a> (HTML to MP4).</p><p><a href="https://x.com/rauchg/status/2045995362499076169" target="_blank" rel="noreferrer">Vercel was breached</a> via an employee’s account on another AI product. Vercel says affected customers have already been contacted. <a href="https://x.com/BrendanFalk/status/2045953132770025769" target="_blank" rel="noreferrer">Quick check</a> to make sure you’re safe.</p><p>Three OpenAI leaders left the company - <a href="https://x.com/kevinweil/status/2045230426210648348" target="_blank" rel="noreferrer">Kevin Weil</a> (CPO, then OpenAI for Science lead), <a href="https://x.com/billpeeb/status/2045225014807670949" target="_blank" rel="noreferrer">Bill Peebles</a> (Sora co-creator), and <a href="https://x.com/snsf/status/2045261554484986155" target="_blank" rel="noreferrer">Srinivas Narayanan</a> (CTO for B2B Applications).</p><p>Skill drops: <a href="https://x.com/nickbaumann_/status/2046422115205960165" target="_blank" rel="noreferrer">skill-creator</a>, <a href="https://x.com/jakubkrehel/status/2045895877588361723" target="_blank" rel="noreferrer">make-interfaces-feel-better</a>, and <a href="https://x.com/LexnLin/status/2045238677589147726" target="_blank" rel="noreferrer">gpt-taste</a> for Codex.</p><p>Afters</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',42)])])}const d=t(o,[["render",n]]);export{m as __pageData,d as default};
